INSERT INTO ge10_lessons (id, subject, grade_tier, topic, title, theory, category, examples, practice_points, difficulty, is_standard, topic_id)
VALUES (
  'cs_se_05', 'cs_software_engineering', 13,
  'Kiáº¿n trÃºc & Máº«u thiáº¿t káº¿ (Design Patterns)',
  'Design Patterns GoF: Singleton, Factory, Strategy, Observer',
  E'## Giá»›i thiá»‡u Design Patterns\n\n**"Gang of Four" (GoF)** â€” Erich Gamma, Richard Helm, Ralph Johnson, John Vlissides â€” xuáº¥t báº£n cuá»‘n "Design Patterns: Elements of Reusable Object-Oriented Software" (1994), Ä‘á»‹nh nghÄ©a 23 pattern chia thÃ nh 3 nhÃ³m:\n\n| NhÃ³m | Má»¥c Ä‘Ã­ch | Pattern tiÃªu biá»ƒu |\n|------|---------|------------------|\n| **Creational** | Táº¡o object linh hoáº¡t | Singleton, Factory, Builder, Prototype |\n| **Structural** | Tá»• chá»©c class vÃ  object | Adapter, Decorator, Facade, Proxy |\n| **Behavioral** | Giao tiáº¿p giá»¯a objects | Strategy, Observer, Command, Iterator |\n\n---\n\n## 1. Singleton Pattern (Creational)\n\n**Má»¥c Ä‘Ã­ch:** Äáº£m báº£o chá»‰ cÃ³ **duy nháº¥t 1 instance** cá»§a má»™t class tá»“n táº¡i trong toÃ n bá»™ á»©ng dá»¥ng.\n\n```java\npublic class DatabaseConnection {\n    // Biáº¿n static giá»¯ instance duy nháº¥t\n    private static DatabaseConnection instance;\n    \n    // Constructor private â€” khÃ´ng ai new trá»±c tiáº¿p Ä‘Æ°á»£c\n    private DatabaseConnection() {\n        // káº¿t ná»‘i DB\n    }\n    \n    // Thread-safe vá»›i synchronized\n    public static synchronized DatabaseConnection getInstance() {\n        if (instance == null) {\n            instance = new DatabaseConnection();\n        }\n        return instance;\n    }\n}\n\n// Sá»­ dá»¥ng\nDatabaseConnection db1 = DatabaseConnection.getInstance();\nDatabaseConnection db2 = DatabaseConnection.getInstance();\nassert db1 == db2; // true â€” cÃ¹ng 1 instance\n```\n\n**DÃ¹ng khi:** Connection pool, Logger, Configuration manager, Cache.\n**NhÆ°á»£c Ä‘iá»ƒm:** KhÃ³ unit test vÃ¬ global state; anti-pattern trong má»™t sá»‘ context.\n\n---\n\n## 2. Factory Method Pattern (Creational)\n\n**Má»¥c Ä‘Ã­ch:** Äá»‹nh nghÄ©a interface Ä‘á»ƒ táº¡o object, nhÆ°ng Ä‘á»ƒ subclass quyáº¿t Ä‘á»‹nh **loáº¡i object nÃ o** Ä‘Æ°á»£c táº¡o ra.\n\n```java\n// Abstract Factory\ninterface NotificationSender {\n    void send(String message);\n}\n\n// Concrete Products\nclass EmailSender implements NotificationSender {\n    public void send(String msg) { /* gá»­i email */ }\n}\nclass SmsSender implements NotificationSender {\n    public void send(String msg) { /* gá»­i SMS */ }\n}\nclass PushSender implements NotificationSender {\n    public void send(String msg) { /* push notification */ }\n}\n\n// Factory\nclass NotificationFactory {\n    public static NotificationSender create(String type) {\n        return switch (type) {\n            case "email" -> new EmailSender();\n            case "sms"   -> new SmsSender();\n            case "push"  -> new PushSender();\n            default -> throw new IllegalArgumentException();\n        };\n    }\n}\n\n// Client code â€” khÃ´ng cáº§n biáº¿t class cá»¥ thá»ƒ\nNotificationSender sender = NotificationFactory.create("email");\nsender.send("ÄÆ¡n hÃ ng Ä‘Ã£ xÃ¡c nháº­n");\n```\n\n---\n\n## 3. Strategy Pattern (Behavioral)\n\n**Má»¥c Ä‘Ã­ch:** Äá»‹nh nghÄ©a má»™t *há»* cÃ¡c thuáº­t toÃ¡n, Ä‘Ã³ng gÃ³i tá»«ng cÃ¡i, vÃ  cho phÃ©p **hoÃ¡n Ä‘á»•i** chÃºng lÃºc runtime.\n\n```java\n// Strategy Interface\ninterface SortStrategy {\n    void sort(int[] data);\n}\n\n// CÃ¡c thuáº­t toÃ¡n cá»¥ thá»ƒ\nclass QuickSort implements SortStrategy {\n    public void sort(int[] data) { /* quicksort */ }\n}\nclass MergeSort implements SortStrategy {\n    public void sort(int[] data) { /* mergesort */ }\n}\n\n// Context â€” inject strategy\nclass Sorter {\n    private SortStrategy strategy;\n    \n    public Sorter(SortStrategy strategy) {\n        this.strategy = strategy;\n    }\n    \n    public void setStrategy(SortStrategy strategy) {\n        this.strategy = strategy; // Ä‘á»•i lÃºc runtime\n    }\n    \n    public void sort(int[] data) {\n        strategy.sort(data); // delegate\n    }\n}\n\n// DÃ¹ng\nSorter sorter = new Sorter(new QuickSort());\nsorter.sort(data);               // dÃ¹ng quicksort\nsorter.setStrategy(new MergeSort());\nsorter.sort(data);               // Ä‘á»•i sang mergesort\n```\n\n---\n\n## 4. Observer Pattern (Behavioral)\n\n**Má»¥c Ä‘Ã­ch:** Khi object (Subject) thay Ä‘á»•i tráº¡ng thÃ¡i â†’ táº¥t cáº£ object phá»¥ thuá»™c (Observers) **Ä‘Æ°á»£c thÃ´ng bÃ¡o tá»± Ä‘á»™ng**.\n\n```java\nimport java.util.*;\n\n// Observer Interface\ninterface Observer {\n    void update(String event, Object data);\n}\n\n// Subject\nclass EventBus {\n    private Map<String, List<Observer>> listeners = new HashMap<>();\n    \n    public void subscribe(String event, Observer observer) {\n        listeners.computeIfAbsent(event, k -> new ArrayList<>()).add(observer);\n    }\n    \n    public void publish(String event, Object data) {\n        listeners.getOrDefault(event, List.of())\n                 .forEach(obs -> obs.update(event, data));\n    }\n}\n\n// Concrete Observers\nclass EmailNotifier implements Observer {\n    public void update(String event, Object data) {\n        System.out.println("Email sent for: " + event);\n    }\n}\n\n// Sá»­ dá»¥ng\nEventBus bus = new EventBus();\nbus.subscribe("order.placed", new EmailNotifier());\nbus.subscribe("order.placed", new SmsNotifier());\nbus.publish("order.placed", orderData); // cáº£ 2 Ä‘á»u nháº­n\n```\n\n**á»¨ng dá»¥ng thá»±c táº¿ cá»§a Observer:** React useState + useEffect, Redux store subscription, Node.js EventEmitter, Java Swing event listeners.\n\n---\n\n## Tá»•ng káº¿t nhanh\n\n| Pattern | Giáº£i quyáº¿t váº¥n Ä‘á» | Keyword |\n|---------|------------------|--------|\n| Singleton | "Chá»‰ cáº§n 1 instance" | `private constructor`, `getInstance()` |\n| Factory | "Táº¡o object mÃ  khÃ´ng dÃ¹ng new trá»±c tiáº¿p" | `create()`, polymorphism |\n| Strategy | "Äá»•i thuáº­t toÃ¡n lÃºc runtime" | `setStrategy()`, delegation |\n| Observer | "Tá»± Ä‘á»™ng thÃ´ng bÃ¡o khi state thay Ä‘á»•i" | `subscribe()`, `publish()` |',
  'core-theory',
  '["Spring Framework (Java) dÃ¹ng Factory Pattern á»Ÿ má»i nÆ¡i: ApplicationContext lÃ  Factory táº¡o ra táº¥t cáº£ Beans.", "React hooks lÃ  Observer Pattern: useState trigger re-render (notify) táº¥t cáº£ components Ä‘ang dÃ¹ng state Ä‘Ã³ khi giÃ¡ trá»‹ thay Ä‘á»•i."]'::jsonb,
  '["Singleton lÃ  pattern dá»… bá»‹ láº¡m dá»¥ng nháº¥t â€” nÃ³ táº¡o ra global state ngáº§m, lÃ m cho code khÃ³ test vÃ  debug. Æ¯u tiÃªn Dependency Injection thay vÃ¬ Singleton khi cÃ³ thá»ƒ.", "Strategy Pattern khÃ¡c vá»›i Template Method: Strategy inject toÃ n bá»™ algorithm tá»« ngoÃ i, Template Method Ä‘á»‹nh nghÄ©a skeleton algorithm cá»‘ Ä‘á»‹nh nhÆ°ng Ä‘á»ƒ subclass Ä‘iá»n cÃ¡c bÆ°á»›c cá»¥ thá»ƒ.", "Observer vÃ  Event-Driven Architecture lÃ  cÃ¹ng má»™t Ã½ tÆ°á»Ÿng á»Ÿ 2 cáº¥p Ä‘á»™ khÃ¡c nhau: Observer trong 1 process, Event Bus/Message Queue (Kafka, RabbitMQ) giá»¯a nhiá»u service."]'::jsonb,
  6, TRUE, 'architecture-design'
)
