-- BÃ€I 6: NguyÃªn lÃ½ SOLID
-- ==========================================
INSERT INTO ge10_lessons (id, subject, grade_tier, topic, title, theory, category, examples, practice_points, difficulty, is_standard, topic_id)
VALUES (
  'cs_se_06', 'cs_software_engineering', 13,
  'Kiá»ƒm thá»­, SOLID & CI/CD',
  'NguyÃªn lÃ½ SOLID trong thiáº¿t káº¿ hÆ°á»›ng Ä‘á»‘i tÆ°á»£ng',
  E'## Giá»›i thiá»‡u SOLID\n\n**SOLID** lÃ  bá»™ 5 nguyÃªn lÃ½ thiáº¿t káº¿ hÆ°á»›ng Ä‘á»‘i tÆ°á»£ng do Robert C. Martin (Uncle Bob) Ä‘á» xuáº¥t, giÃºp táº¡o ra code dá»… báº£o trÃ¬, má»Ÿ rá»™ng vÃ  test.\n\n---\n\n## S â€” Single Responsibility Principle (SRP)\n\n> "Má»™t class chá»‰ nÃªn cÃ³ **má»™t lÃ½ do** Ä‘á»ƒ thay Ä‘á»•i."\n\n```java\n// âŒ Vi pháº¡m SRP â€” UserService lÃ m 3 viá»‡c khÃ¡c nhau\nclass UserService {\n    public User createUser(String name) { /* ... */ }\n    public void sendWelcomeEmail(User user) { /* ... */ }  // â† email logic\n    public void saveToDatabase(User user) { /* ... */ }    // â† DB logic\n}\n\n// âœ… ÄÃºng SRP â€” tÃ¡ch thÃ nh 3 class riÃªng\nclass UserService   { public User createUser(String name) { /* ... */ } }\nclass EmailService  { public void sendWelcome(User user) { /* ... */ } }\nclass UserRepository{ public void save(User user) { /* ... */ } }\n```\n\n**Lá»£i Ã­ch:** Thay Ä‘á»•i logic email khÃ´ng áº£nh hÆ°á»Ÿng Ä‘áº¿n logic táº¡o user.\n\n---\n\n## O â€” Open/Closed Principle (OCP)\n\n> "Má»Ÿ Ä‘á»ƒ **má»Ÿ rá»™ng**, Ä‘Ã³ng Ä‘á»ƒ **sá»­a Ä‘á»•i**." (Open for extension, Closed for modification)\n\n```java\n// âŒ Vi pháº¡m OCP â€” thÃªm loáº¡i discount má»›i pháº£i sá»­a class cÅ©\nclass DiscountCalculator {\n    public double calculate(Order order, String type) {\n        if (type.equals("student")) return order.total * 0.1;\n        if (type.equals("senior"))  return order.total * 0.15;\n        // ThÃªm "military" â†’ pháº£i sá»­a class nÃ y â†’ nguy hiá»ƒm\n        return 0;\n    }\n}\n\n// âœ… ÄÃºng OCP â€” thÃªm discount má»›i chá»‰ cáº§n thÃªm class má»›i\ninterface DiscountStrategy {\n    double calculate(Order order);\n}\nclass StudentDiscount  implements DiscountStrategy { public double calculate(Order o) { return o.total * 0.1; } }\nclass SeniorDiscount   implements DiscountStrategy { public double calculate(Order o) { return o.total * 0.15; } }\nclass MilitaryDiscount implements DiscountStrategy { public double calculate(Order o) { return o.total * 0.2; } }\n```\n\n---\n\n## L â€” Liskov Substitution Principle (LSP)\n\n> "Object cá»§a subclass pháº£i **thay tháº¿ Ä‘Æ°á»£c** object cá»§a superclass mÃ  khÃ´ng lÃ m há»ng chÆ°Æ¡ng trÃ¬nh."\n\n```java\n// âŒ Vi pháº¡m LSP â€” Square extends Rectangle nhÆ°ng phÃ¡ vá»¡ hÃ nh vi\nclass Rectangle {\n    void setWidth(int w)  { this.width = w; }\n    void setHeight(int h) { this.height = h; }\n    int getArea()         { return width * height; }\n}\n\nclass Square extends Rectangle {\n    void setWidth(int w)  { this.width = w; this.height = w; } // â† override lÃ m há»ng\n    void setHeight(int h) { this.width = h; this.height = h; } // â† logic khÃ´ng Ä‘Ãºng\n}\n\n// Náº¿u dÃ¹ng Square nhÆ° Rectangle:\nRectangle r = new Square();\nr.setWidth(5);\nr.setHeight(3);\nSystem.out.println(r.getArea()); // expected: 15, actual: 9 â† LSP bá»‹ phÃ¡ vá»¡\n```\n\n**Fix:** DÃ¹ng interface `Shape` vá»›i `getArea()` thay vÃ¬ inheritance.\n\n---\n\n## I â€” Interface Segregation Principle (ISP)\n\n> "Client khÃ´ng nÃªn bá»‹ buá»™c implement **interface mÃ  nÃ³ khÃ´ng dÃ¹ng**."\n\n```java\n// âŒ Vi pháº¡m ISP â€” interface quÃ¡ lá»›n\ninterface Worker {\n    void work();\n    void eat();   // Robot khÃ´ng Äƒn!\n    void sleep(); // Robot khÃ´ng ngá»§!\n}\n\n// âœ… ÄÃºng ISP â€” tÃ¡ch interface nhá»\ninterface Workable { void work(); }\ninterface Eatable  { void eat(); }\ninterface Sleepable{ void sleep(); }\n\nclass HumanWorker implements Workable, Eatable, Sleepable { /* ... */ }\nclass RobotWorker  implements Workable { /* chá»‰ implement nhá»¯ng gÃ¬ cáº§n */ }\n```\n\n---\n\n## D â€” Dependency Inversion Principle (DIP)\n\n> "Module cáº¥p cao khÃ´ng phá»¥ thuá»™c vÃ o module cáº¥p tháº¥p. Cáº£ hai phá»¥ thuá»™c vÃ o **abstraction** (interface/abstract class)."\n\n```java\n// âŒ Vi pháº¡m DIP â€” OrderService phá»¥ thuá»™c trá»±c tiáº¿p vÃ o MySQLDatabase\nclass OrderService {\n    private MySQLDatabase db = new MySQLDatabase(); // â† hardcode, khÃ´ng thá»ƒ Ä‘á»•i\n    public void placeOrder(Order order) {\n        db.save(order);\n    }\n}\n\n// âœ… ÄÃºng DIP â€” phá»¥ thuá»™c vÃ o abstraction\ninterface Database {\n    void save(Object entity);\n}\nclass MySQLDatabase  implements Database { public void save(Object e) { /* MySQL */ } }\nclass MongoDatabase  implements Database { public void save(Object e) { /* Mongo */ } }\n\nclass OrderService {\n    private final Database db; // â† inject tá»« ngoÃ i\n    public OrderService(Database db) { this.db = db; }\n    public void placeOrder(Order order) { db.save(order); }\n}\n\n// DÃ¹ng MySQL hoáº·c Mongo khÃ´ng cáº§n sá»­a OrderService\nnew OrderService(new MySQLDatabase());\nnew OrderService(new MongoDatabase());\n```\n\n---\n\n## TÃ³m táº¯t SOLID\n\n| Chá»¯ | TÃªn | Keyword nhá»› nhanh |\n|-----|-----|-------------------|\n| **S** | Single Responsibility | "1 class = 1 nhiá»‡m vá»¥" |\n| **O** | Open/Closed | "ThÃªm khÃ´ng sá»­a" |\n| **L** | Liskov Substitution | "Subclass thay tháº¿ Ä‘Æ°á»£c superclass" |\n| **I** | Interface Segregation | "Interface nhá», Ä‘Ãºng nhu cáº§u" |\n| **D** | Dependency Inversion | "Phá»¥ thuá»™c vÃ o abstraction, khÃ´ng pháº£i implementation" |',
  'core-theory',
  '["Spring Framework (Java) Ã¡p dá»¥ng DIP xuyÃªn suá»‘t: @Autowired tá»± Ä‘á»™ng inject interface, khÃ´ng cáº§n new. Test chá»‰ cáº§n inject mock object.", "Uncle Bob (Robert C. Martin) â€” tÃ¡c giáº£ SOLID â€” cÃ³ cÃ¢u nÃ³i ná»•i tiáº¿ng: Clean code reads like well-written prose. SOLID lÃ  ngá»¯ phÃ¡p cá»§a clean code Ä‘Ã³."]'::jsonb,
  '["SOLID khÃ´ng pháº£i luáº­t tuyá»‡t Ä‘á»‘i: Ã¡p dá»¥ng cá»©ng nháº¯c vÃ o code nhá» Ä‘Æ¡n giáº£n sáº½ gÃ¢y over-engineering. DÃ¹ng khi code Ä‘ang phá»©c táº¡p vÃ  khÃ³ thay Ä‘á»•i.", "OCP vÃ  Strategy Pattern cÃ³ liÃªn quan cháº·t cháº½: Strategy lÃ  cÃ¡ch implement OCP báº±ng composition thay vÃ¬ inheritance.", "DIP khÃ´ng pháº£i Dependency Injection (DI) â€” DIP lÃ  nguyÃªn lÃ½ thiáº¿t káº¿, DI (Spring, Angular) lÃ  ká»¹ thuáº­t Ä‘á»ƒ Ã¡p dá»¥ng DIP."]'::jsonb,
  6, TRUE, 'quality-testing'
)
ON CONFLICT (id) DO UPDATE SET theory = EXCLUDED.theory, examples = EXCLUDED.examples, practice_points = EXCLUDED.practice_points;

-- ==========================================
-- BÃ€I 7: Kiá»ƒm thá»­ pháº§n má»m
-- ==========================================
INSERT INTO ge10_lessons (id, subject, grade_tier, topic, title, theory, category, examples, practice_points, difficulty, is_standard, topic_id)
VALUES (
  'cs_se_07', 'cs_software_engineering', 13,
  'Kiá»ƒm thá»­, SOLID & CI/CD',
  'CÃ¡c cáº¥p Ä‘á»™ kiá»ƒm thá»­ pháº§n má»m (Unit, Integration, System, Acceptance)',
  E'## Kim tá»± thÃ¡p Kiá»ƒm thá»­ (Test Pyramid)\n\nMike Cohn Ä‘á» xuáº¥t mÃ´ hÃ¬nh phÃ¢n táº§ng kiá»ƒm thá»­, trong Ä‘Ã³ test náº±m á»Ÿ **Ä‘Ã¡y kim tá»± thÃ¡p cÃ ng nhiá»u, chi phÃ­ cÃ ng tháº¥p vÃ  tá»‘c Ä‘á»™ cÃ ng nhanh**.\n\n```\n         â•±â•²\n        â•± E2Eâ•²        â† Ãt nháº¥t, cháº­m nháº¥t, Ä‘áº¯t nháº¥t\n       â•±â”€â”€â”€â”€â”€â”€â•²\n      â•±Integra-â•²\n     â•±  tion    â•²     â† Vá»«a pháº£i\n    â•±â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â•²\n   â•±   Unit Tests â•²   â† Nhiá»u nháº¥t, nhanh nháº¥t, ráº» nháº¥t\n  â•±â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â•²\n```\n\n---\n\n## 1. Unit Testing (Kiá»ƒm thá»­ Ä‘Æ¡n vá»‹)\n\n**Pháº¡m vi:** Test má»™t function/method/class **Ä‘á»™c láº­p** â€” isolate hoÃ n toÃ n khá»i database, network, file system báº±ng **mocks vÃ  stubs**.\n\n```java\n// Class cáº§n test\nclass Calculator {\n    public int divide(int a, int b) {\n        if (b == 0) throw new ArithmeticException("Cannot divide by zero");\n        return a / b;\n    }\n}\n\n// Unit Test vá»›i JUnit 5\n@Test\nvoid divide_normalCase_returnsCorrectResult() {\n    Calculator calc = new Calculator();\n    assertEquals(5, calc.divide(10, 2));   // happy path\n}\n\n@Test\nvoid divide_byZero_throwsException() {\n    Calculator calc = new Calculator();\n    assertThrows(ArithmeticException.class,\n                 () -> calc.divide(10, 0)); // edge case\n}\n```\n\n**Frameworks phá»• biáº¿n:**\n- Java: JUnit + Mockito\n- Python: pytest + unittest.mock\n- JavaScript: Jest + sinon\n- C#: NUnit + Moq\n\n**Äá»™ phá»§ test (Coverage):** Code coverage Ä‘o % dÃ²ng code Ä‘Æ°á»£c cháº¡y qua test. 80% lÃ  ngÆ°á»¡ng thá»±c táº¿ nhiá»u team Ä‘áº·t ra â€” nhÆ°ng 100% coverage khÃ´ng cÃ³ nghÄ©a lÃ  khÃ´ng bug.\n\n---\n\n## 2. Integration Testing\n\n**Pháº¡m vi:** Test **sá»± káº¿t há»£p** cá»§a nhiá»u component vá»›i nhau â€” cÃ³ thá»ƒ cÃ³ database tháº­t, API tháº­t.\n\n```java\n// Test API endpoint + Database tháº­t\n@SpringBootTest\n@AutoConfigureMockMvc\nclass UserControllerIntegrationTest {\n    @Autowired MockMvc mockMvc;\n    \n    @Test\n    void createUser_validData_returns201() throws Exception {\n        mockMvc.perform(post("/api/users")\n                .contentType(MediaType.APPLICATION_JSON)\n                .content("""{"name": "Alice", "email": "alice@test.com"}"""))\n               .andExpect(status().isCreated())\n               .andExpect(jsonPath("$.id").exists());\n    }\n}\n```\n\n---\n\n## 3. System Testing\n\n**Pháº¡m vi:** Test toÃ n bá»™ há»‡ thá»‘ng Ä‘Ã£ tÃ­ch há»£p hoÃ n chá»‰nh trong mÃ´i trÆ°á»ng gáº§n vá»›i production.\n\nLoáº¡i test trong System Testing:\n- **Functional Testing:** Chá»©c nÄƒng cÃ³ Ä‘Ãºng yÃªu cáº§u khÃ´ng?\n- **Performance Testing:** Response time, throughput dÆ°á»›i táº£i.\n- **Load Testing:** Há»‡ thá»‘ng chá»‹u Ä‘Æ°á»£c bao nhiÃªu concurrent users?\n- **Stress Testing:** Há»‡ thá»‘ng hÃ nh xá»­ tháº¿ nÃ o khi quÃ¡ táº£i?\n- **Security Testing:** CÃ³ lá»— há»•ng SQL injection, XSS, auth bypass khÃ´ng?\n\n```bash\n# VÃ­ dá»¥ dÃ¹ng k6 load testing\nexport default function () {\n  const res = http.get("https://api.example.com/users");\n  check(res, {\n    "status is 200": (r) => r.status === 200,\n    "response time < 200ms": (r) => r.timings.duration < 200,\n  });\n}\n# k6 run --vus 1000 --duration 60s script.js\n```\n\n---\n\n## 4. Acceptance Testing (UAT)\n\n**Pháº¡m vi:** **NgÆ°á»i dÃ¹ng thá»±c táº¿ hoáº·c QA** kiá»ƒm tra xem há»‡ thá»‘ng cÃ³ Ä‘Ã¡p á»©ng yÃªu cáº§u business khÃ´ng.\n\n- **UAT (User Acceptance Testing):** KhÃ¡ch hÃ ng/end-user tá»± test.\n- **Alpha testing:** Test ná»™i bá»™ táº¡i nhÃ  phÃ¡t triá»ƒn.\n- **Beta testing:** Release cho nhÃ³m ngÆ°á»i dÃ¹ng giá»›i háº¡n trÆ°á»›c khi launch.\n\n---\n\n## 5. Black Box vs White Box Testing\n\n| TiÃªu chÃ­ | Black Box | White Box |\n|----------|-----------|----------|\n| Kiáº¿n thá»©c code | KhÃ´ng cáº§n | Cáº§n |\n| Test dá»±a trÃªn | Input/Output | Cáº¥u trÃºc code bÃªn trong |\n| Ai thá»±c hiá»‡n | QA, Business Analyst | Developer |\n| VÃ­ dá»¥ | Acceptance Test, System Test | Unit Test, Code Coverage |\n\n---\n\n## 6. TDD â€” Test-Driven Development\n\nTDD lÃ  ká»¹ thuáº­t viáº¿t **test trÆ°á»›c, code sau** theo chu ká»³ Red-Green-Refactor:\n\n```\nâ‘  Red   â†’ Viáº¿t test (fail vÃ¬ chÆ°a cÃ³ code)\nâ‘¡ Green â†’ Viáº¿t code tá»‘i thiá»ƒu Ä‘á»ƒ test pass\nâ‘¢ Refactor â†’ Cáº£i thiá»‡n code khÃ´ng lÃ m test fail\n    â†“\n   Láº·p láº¡i\n```\n\n**Lá»£i Ã­ch:** Code luÃ´n cÃ³ test coverage, thiáº¿t káº¿ thÆ°á»ng tá»‘t hÆ¡n (pháº£i viáº¿t testable code), phÃ¡t hiá»‡n regression sá»›m.',
  'core-theory',
  '["Google ná»•i tiáº¿ng vá»›i 70-20-10 rule cho test pyramid: 70% unit test, 20% integration test, 10% E2E test. Tá»· lá»‡ nÃ y giÃºp giá»¯ CI pipeline cháº¡y nhanh dÆ°á»›i 10 phÃºt.", "Selenium vÃ  Cypress lÃ  2 framework E2E testing phá»• biáº¿n nháº¥t cho web app. Playwright (Microsoft) Ä‘ang chiáº¿m thá»‹ pháº§n nhanh nhá» há»— trá»£ Ä‘a browser vÃ  API dá»… dÃ¹ng."]'::jsonb,
  '["Test coverage 100% khÃ´ng báº£o Ä‘áº£m khÃ´ng cÃ³ bug: náº¿u test case sai logic, coverage cao váº«n vÃ´ nghÄ©a. Mutation testing (PIT) lÃ  cÃ¡ch kiá»ƒm tra cháº¥t lÆ°á»£ng cá»§a test case.", "Integration test cháº¡y cháº­m hÆ¡n Unit test vÃ¬ pháº£i khá»Ÿi Ä‘á»™ng DB vÃ  network. DÃ¹ng @TestContainers Ä‘á»ƒ cháº¡y DB trong Docker riÃªng cho test.", "UAT khÃ´ng pháº£i QA Testing: UAT do business user thá»±c hiá»‡n Ä‘á»ƒ xÃ¡c nháº­n yÃªu cáº§u nghiá»‡p vá»¥, QA test Ä‘á»ƒ tÃ¬m bug ká»¹ thuáº­t."]'::jsonb,
