-- ==========================================
-- BÃ€I 8: CI/CD & DevOps
-- ==========================================
INSERT INTO ge10_lessons (id, subject, grade_tier, topic, title, theory, category, examples, practice_points, difficulty, is_standard, topic_id)
VALUES (
  'cs_se_08', 'cs_software_engineering', 13,
  'Kiá»ƒm thá»­, SOLID & CI/CD',
  'CI/CD Pipeline & DevOps: Tá»± Ä‘á»™ng hÃ³a Build, Test, Deploy',
  E'## 1. CI/CD lÃ  gÃ¬?\n\n**CI (Continuous Integration):** Má»—i khi developer push code â†’ tá»± Ä‘á»™ng build vÃ  cháº¡y test ngay láº­p tá»©c, phÃ¡t hiá»‡n lá»—i sá»›m.\n\n**CD (Continuous Delivery/Deployment):**\n- **Continuous Delivery:** Tá»± Ä‘á»™ng chuáº©n bá»‹ release lÃªn staging â€” nhÆ°ng deploy production cáº§n ngÆ°á»i báº¥m nÃºt.\n- **Continuous Deployment:** Tá»± Ä‘á»™ng deploy tháº³ng lÃªn production náº¿u táº¥t cáº£ test pass â€” khÃ´ng cáº§n ngÆ°á»i can thiá»‡p.\n\n---\n\n## 2. CI/CD Pipeline Ä‘iá»ƒn hÃ¬nh\n\n```\nDeveloper\n    â”‚  git push\n    â†“\nâ”Œâ”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”\nâ”‚                  CI/CD Pipeline                      â”‚\nâ”‚                                                      â”‚\nâ”‚  Code â†’ Build â†’ Unit Test â†’ Integration Test         â”‚\nâ”‚                                    â”‚                 â”‚\nâ”‚                            Static Analysis           â”‚\nâ”‚                         (SonarQube, ESLint)          â”‚\nâ”‚                                    â”‚                 â”‚\nâ”‚                            Security Scan             â”‚\nâ”‚                            (SAST, DAST)              â”‚\nâ”‚                                    â”‚                 â”‚\nâ”‚                        Build Docker Image            â”‚\nâ”‚                                    â”‚                 â”‚\nâ”‚                        Deploy to Staging             â”‚\nâ”‚                                    â”‚                 â”‚\nâ”‚                        E2E Test on Staging           â”‚\nâ”‚                                    â”‚                 â”‚\nâ”‚              â”Œâ”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”¤                 â”‚\nâ”‚              â–¼                     â–¼                 â”‚\nâ”‚        Manual Gate          Auto Deploy              â”‚\nâ”‚       (CD Delivery)        (CD Deployment)           â”‚\nâ”‚              â”‚                     â”‚                 â”‚\nâ”‚              â””â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”˜                 â”‚\nâ”‚                            â”‚                         â”‚\nâ”‚                     Deploy Production                â”‚\nâ””â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”˜\n```\n\n---\n\n## 3. CÃ¡c cÃ´ng cá»¥ CI/CD phá»• biáº¿n\n\n| CÃ´ng cá»¥ | Äáº·c Ä‘iá»ƒm | Phá»• biáº¿n á»Ÿ |\n|---------|---------|------------|\n| **GitHub Actions** | TÃ­ch há»£p native vá»›i GitHub, YAML config | Open source, startups |\n| **GitLab CI** | All-in-one DevOps platform | Enterprise |\n| **Jenkins** | Open source, plugin ecosystem khá»•ng lá»“ | On-premise enterprise |\n| **CircleCI** | Fast, cloud-native | SaaS companies |\n| **ArgoCD** | GitOps cho Kubernetes | Cloud-native |\n\n---\n\n## 4. VÃ­ dá»¥ GitHub Actions workflow\n\n```yaml\n# .github/workflows/ci.yml\nname: CI Pipeline\n\non:\n  push:\n    branches: [main, develop]\n  pull_request:\n    branches: [main]\n\njobs:\n  test:\n    runs-on: ubuntu-latest\n    \n    services:\n      postgres:\n        image: postgres:15\n        env:\n          POSTGRES_PASSWORD: test\n        options: >-\n          --health-cmd pg_isready\n          --health-interval 10s\n    \n    steps:\n      - uses: actions/checkout@v4\n      \n      - name: Setup Node.js\n        uses: actions/setup-node@v4\n        with:\n          node-version: \'20\'\n          cache: \'npm\'\n      \n      - name: Install dependencies\n        run: npm ci\n      \n      - name: Run unit tests\n        run: npm test -- --coverage\n      \n      - name: Run integration tests\n        run: npm run test:integration\n        env:\n          DATABASE_URL: postgresql://postgres:test@localhost:5432/testdb\n      \n      - name: Upload coverage to Codecov\n        uses: codecov/codecov-action@v4\n  \n  deploy-staging:\n    needs: test\n    if: github.ref == \'refs/heads/main\'\n    runs-on: ubuntu-latest\n    steps:\n      - name: Deploy to staging\n        run: echo "Deploy to Vercel/Railway staging"\n```\n\n---\n\n## 5. Docker trong CI/CD\n\nDocker container hÃ³a á»©ng dá»¥ng â€” Ä‘áº£m báº£o **"works on my machine" â†’ works everywhere**.\n\n```dockerfile\n# Dockerfile cho Node.js app\nFROM node:20-alpine AS builder\nWORKDIR /app\nCOPY package*.json ./\nRUN npm ci --only=production\nCOPY . .\nRUN npm run build\n\nFROM node:20-alpine AS runner\nWORKDIR /app\nCOPY --from=builder /app/dist ./dist\nCOPY --from=builder /app/node_modules ./node_modules\nEXPOSE 3000\nCMD ["node", "dist/server.js"]\n```\n\n**Multi-stage build:** Builder stage cÃ i Ä‘á»§ dev tools, Runner stage chá»‰ giá»¯ production artifacts â†’ image nhá» hÆ¡n vÃ  an toÃ n hÆ¡n.\n\n---\n\n## 6. Metrics Ä‘o lÆ°á»ng CI/CD hiá»‡u quáº£ (DORA Metrics)\n\n| Metric | Ã nghÄ©a | Target (Elite) |\n|--------|---------|----------------|\n| **Deployment Frequency** | Bao lÃ¢u deploy 1 láº§n | Multiple/day |\n| **Lead Time for Changes** | Tá»« commit Ä‘áº¿n production | < 1 giá» |\n| **Change Failure Rate** | % deploy gÃ¢y lá»—i | < 5% |\n| **MTTR (Mean Time to Restore)** | Thá»i gian khÃ´i phá»¥c khi cÃ³ sá»± cá»‘ | < 1 giá» |',
  'core-theory',
  '["Netflix deploy 100+ láº§n má»—i ngÃ y lÃªn production mÃ  khÃ´ng downtime. Há» dÃ¹ng Canary deployment: deploy cho 1% users trÆ°á»›c, monitor, rá»“i rollout dáº§n.", "Vercel (dÃ¹ng cho frontend) vÃ  Railway (backend) lÃ  2 platform CI/CD phá»• biáº¿n nháº¥t cho indie developer vÃ  startup â€” push code lÃªn GitHub lÃ  tá»± Ä‘á»™ng deploy."]'::jsonb,
  '["CI khÃ¡c CD vá» scope: CI cháº¡y trÃªn má»—i commit/PR Ä‘á»ƒ phÃ¡t hiá»‡n lá»—i nhanh, CD lÃ  pipeline hoÃ n chá»‰nh tá»« code Ä‘áº¿n production.", "Feature flags (LaunchDarkly, flagsmith) cho phÃ©p deploy code nhÆ°ng táº¯t tÃ­nh nÄƒng â€” tÃ¡ch biá»‡t deployment vÃ  release.", "Kubernetes khÃ´ng pháº£i Ä‘iá»u kiá»‡n báº¯t buá»™c cho CI/CD: nhiá»u team thÃ nh cÃ´ng vá»›i CI/CD Ä‘Æ¡n giáº£n trÃªn Heroku, Railway, Render mÃ  khÃ´ng cáº§n K8s."]'::jsonb,
  6, TRUE, 'quality-testing'
)
