-- ==========================================
-- BÃ€I 9: Sequence Diagram & Thiáº¿t káº¿ API
-- ==========================================
INSERT INTO ge10_lessons (id, subject, grade_tier, topic, title, theory, category, examples, practice_points, difficulty, is_standard, topic_id)
VALUES (
  'cs_se_09', 'cs_software_engineering', 13,
  'PhÃ¢n tÃ­ch YÃªu cáº§u & UML',
  'Sequence Diagram UML & Thiáº¿t káº¿ RESTful API',
  E'## 1. Sequence Diagram UML\n\nSequence Diagram thá»ƒ hiá»‡n **chuá»—i tÆ°Æ¡ng tÃ¡c theo thá»i gian** giá»¯a cÃ¡c objects/components Ä‘á»ƒ hoÃ n thÃ nh má»™t use case cá»¥ thá»ƒ.\n\n### CÃº phÃ¡p vÃ  kÃ½ hiá»‡u\n\n```\nClient          Controller        Service          Database\n  â”‚                 â”‚                â”‚                â”‚\n  â”‚ POST /orders    â”‚                â”‚                â”‚\n  â”‚â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€>â”‚                â”‚                â”‚\n  â”‚                 â”‚ createOrder()  â”‚                â”‚\n  â”‚                 â”‚â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€>â”‚                â”‚\n  â”‚                 â”‚                â”‚ validateUser() â”‚\n  â”‚                 â”‚                â”‚â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€>â”‚\n  â”‚                 â”‚                â”‚<â”€ â”€ â”€ â”€ â”€ â”€ â”€ â”‚\n  â”‚                 â”‚                â”‚  User data     â”‚\n  â”‚                 â”‚                â”‚ saveOrder()    â”‚\n  â”‚                 â”‚                â”‚â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€>â”‚\n  â”‚                 â”‚                â”‚<â”€ â”€ â”€ â”€ â”€ â”€ â”€ â”‚\n  â”‚                 â”‚                â”‚  orderId       â”‚\n  â”‚                 â”‚<â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”‚                â”‚\n  â”‚                 â”‚ 201 Created    â”‚                â”‚\n  â”‚<â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”‚  {orderId}     â”‚                â”‚\n  â”‚                 â”‚                â”‚                â”‚\n```\n\n**KÃ½ hiá»‡u:**\n- `â”€â”€â”€â”€â”€â”€â”€â”€>` : Synchronous message (request/call)\n- `â”€ â”€ â”€ â”€ >` : Return message (response)\n- HÃ¬nh chá»¯ nháº­t trÃªn lifeline: Activation box (Ä‘ang xá»­ lÃ½)\n- `alt [condition]`: nhÃ¡nh Ä‘iá»u kiá»‡n if/else\n- `loop [n times]`: vÃ²ng láº·p\n- `opt [condition]`: tÃ¹y chá»n\n\n### Khi nÃ o dÃ¹ng Sequence Diagram?\n- TÃ i liá»‡u hÃ³a flow xá»­ lÃ½ cá»§a má»™t API endpoint phá»©c táº¡p.\n- Giáº£i thÃ­ch authentication flow (OAuth 2.0, JWT).\n- Debug vÃ  phÃ¢n tÃ­ch race condition trong há»‡ thá»‘ng phÃ¢n tÃ¡n.\n\n---\n\n## 2. Thiáº¿t káº¿ RESTful API\n\nREST (Representational State Transfer) lÃ  kiáº¿n trÃºc thiáº¿t káº¿ API phá»• biáº¿n nháº¥t, dÃ¹ng HTTP methods Ä‘á»ƒ thao tÃ¡c resources.\n\n### HTTP Methods & CRUD mapping\n\n| HTTP Method | CRUD | Idempotent | Endpoint vÃ­ dá»¥ |\n|-------------|------|-----------|----------------|\n| GET | Read | âœ… | GET /api/orders |\n| POST | Create | âŒ | POST /api/orders |\n| PUT | Update (toÃ n bá»™) | âœ… | PUT /api/orders/123 |\n| PATCH | Update (má»™t pháº§n) | âœ… | PATCH /api/orders/123 |\n| DELETE | Delete | âœ… | DELETE /api/orders/123 |\n\n**Idempotent** = Gá»i nhiá»u láº§n cho cÃ¹ng káº¿t quáº£. Táº¡i sao quan trá»ng: náº¿u máº¡ng yáº¿u, client retry láº¡i sáº½ khÃ´ng táº¡o duplicate.\n\n### Convention Ä‘áº·t tÃªn endpoint\n\n```\n# âœ… ÄÃºng â€” danh tá»« sá»‘ nhiá»u, phÃ¢n cáº¥p rÃµ rÃ ng\nGET    /api/users           # Láº¥y danh sÃ¡ch users\nGET    /api/users/123       # Láº¥y user #123\nPOST   /api/users           # Táº¡o user má»›i\nPUT    /api/users/123       # Cáº­p nháº­t user #123\nDELETE /api/users/123       # XÃ³a user #123\nGET    /api/users/123/orders # ÄÆ¡n hÃ ng cá»§a user #123\n\n# âŒ Sai â€” dÃ¹ng Ä‘á»™ng tá»« trong URL\nGET  /api/getUser\nPOST /api/createUser\nGET  /api/user/getOrders\n```\n\n### HTTP Status Codes quan trá»ng\n\n| Code | TÃªn | DÃ¹ng khi |\n|------|-----|----------|\n| 200 | OK | GET thÃ nh cÃ´ng |\n| 201 | Created | POST táº¡o resource thÃ nh cÃ´ng |\n| 204 | No Content | DELETE thÃ nh cÃ´ng |\n| 400 | Bad Request | Request data khÃ´ng há»£p lá»‡ |\n| 401 | Unauthorized | ChÆ°a Ä‘Äƒng nháº­p |\n| 403 | Forbidden | ÄÄƒng nháº­p nhÆ°ng khÃ´ng cÃ³ quyá»n |\n| 404 | Not Found | Resource khÃ´ng tá»“n táº¡i |\n| 409 | Conflict | TrÃ¹ng láº·p (email Ä‘Ã£ tá»“n táº¡i) |\n| 422 | Unprocessable | Dá»¯ liá»‡u há»£p lá»‡ format nhÆ°ng sai business rule |\n| 429 | Too Many Requests | Rate limit vÆ°á»£t ngÆ°á»¡ng |\n| 500 | Internal Server Error | Lá»—i server khÃ´ng xÃ¡c Ä‘á»‹nh |\n\n### Cáº¥u trÃºc Response JSON chuáº©n\n\n```json\n// ThÃ nh cÃ´ng\n{\n  "success": true,\n  "data": {\n    "id": 123,\n    "name": "Alice"\n  },\n  "meta": {\n    "page": 1,\n    "totalPages": 10\n  }\n}\n\n// Lá»—i\n{\n  "success": false,\n  "error": {\n    "code": "VALIDATION_ERROR",\n    "message": "Email khÃ´ng há»£p lá»‡",\n    "field": "email"\n  }\n}\n```',
  'core-theory',
  '["Swagger/OpenAPI lÃ  chuáº©n tÃ i liá»‡u hÃ³a REST API phá»• biáº¿n nháº¥t. Postman vÃ  Insomnia lÃ  cÃ´ng cá»¥ test API phá»• biáº¿n nháº¥t trong industry.", "Stripe API lÃ  benchmark vÃ ng cho REST API design: nháº¥t quÃ¡n, cÃ³ idempotency key cho payment, error message rÃµ rÃ ng vÃ  cÃ³ code máº«u cho 10+ ngÃ´n ngá»¯."]'::jsonb,
  '["401 vs 403: 401 Unauthorized thá»±c ra nghÄ©a lÃ  Unauthenticated (chÆ°a Ä‘Äƒng nháº­p), 403 Forbidden nghÄ©a lÃ  Unauthorized (Ä‘Äƒng nháº­p nhÆ°ng thiáº¿u quyá»n) â€” tÃªn gá»i trong HTTP spec bá»‹ nháº§m láº«n tá»« ban Ä‘áº§u.", "PUT pháº£i gá»­i toÃ n bá»™ object (partial update sáº½ reset cÃ¡c field khÃ´ng gá»­i vá» null), PATCH chá»‰ gá»­i field cáº§n thay Ä‘á»•i.", "GraphQL vÃ  gRPC lÃ  2 alternative cá»§a REST: GraphQL cho phÃ©p client query Ä‘Ãºng field cáº§n, gRPC dÃ¹ng binary format nhanh hÆ¡n cho microservices internal."]'::jsonb,
  6, TRUE, 'software-requirements'
)
ON CONFLICT (id) DO UPDATE SET theory = EXCLUDED.theory, examples = EXCLUDED.examples, practice_points = EXCLUDED.practice_points;

-- ==========================================
-- BÃ€I 10: Code Review, Refactoring & Tech Debt
-- ==========================================
INSERT INTO ge10_lessons (id, subject, grade_tier, topic, title, theory, category, examples, practice_points, difficulty, is_standard, topic_id)
VALUES (
  'cs_se_10', 'cs_software_engineering', 13,
  'Kiá»ƒm thá»­, SOLID & CI/CD',
  'Code Review, TÃ¡i cáº¥u trÃºc mÃ£ (Refactoring) & Ná»£ ká»¹ thuáº­t',
  E'## 1. Code Review â€” VÃ¬ sao quan trá»ng?\n\nCode Review lÃ  quÃ¡ trÃ¬nh developer khÃ¡c Ä‘á»c vÃ  Ä‘Ã¡nh giÃ¡ code trÆ°á»›c khi merge vÃ o main branch. Google nghiÃªn cá»©u ná»™i bá»™ cho tháº¥y Code Review giáº£m bug lÃªn Ä‘áº¿n **60%**.\n\n### Má»¥c tiÃªu cá»§a Code Review\n- **PhÃ¡t hiá»‡n bug** trÆ°á»›c khi vÃ o production.\n- **Knowledge sharing**: cáº£ team hiá»ƒu codebase, khÃ´ng pháº£i chá»‰ ngÆ°á»i viáº¿t.\n- **Nháº¥t quÃ¡n code style**: giá»¯ code dá»… Ä‘á»c vÃ  báº£o trÃ¬.\n- **Thiáº¿t káº¿ tá»‘t hÆ¡n**: reviewer cÃ³ thá»ƒ gÃ³p Ã½ kiáº¿n trÃºc.\n\n### Checklist Code Review tá»‘t\n\n```\nâœ… Correctness\n   â–¡ Logic cÃ³ Ä‘Ãºng khÃ´ng?\n   â–¡ Edge case Ä‘Æ°á»£c xá»­ lÃ½ chÆ°a? (null, empty, overflow)\n   â–¡ CÃ³ race condition hoáº·c deadlock khÃ´ng?\n\nâœ… Security\n   â–¡ Input Ä‘Æ°á»£c validate vÃ  sanitize chÆ°a?\n   â–¡ KhÃ´ng cÃ³ hardcode password/API key?\n   â–¡ SQL query cÃ³ dÃ¹ng parameterized? (chá»‘ng injection)\n\nâœ… Performance\n   â–¡ CÃ³ N+1 query khÃ´ng?\n   â–¡ VÃ²ng láº·p lá»“ng nhau cÃ³ thá»ƒ tá»‘i Æ°u khÃ´ng?\n   â–¡ Cache Ä‘Æ°á»£c dÃ¹ng Ä‘Ãºng chá»— chÆ°a?\n\nâœ… Maintainability\n   â–¡ TÃªn biáº¿n/hÃ m cÃ³ rÃµ rÃ ng khÃ´ng?\n   â–¡ Function khÃ´ng quÃ¡ 20-30 dÃ²ng?\n   â–¡ CÃ³ test cho code má»›i khÃ´ng?\n```\n\n---\n\n## 2. Code Smells â€” Dáº¥u hiá»‡u Code Cáº§n Refactor\n\n**Code smell** lÃ  dáº¥u hiá»‡u trong code cho tháº¥y cÃ³ váº¥n Ä‘á» tiá»m áº©n, dÃ¹ code cÃ³ thá»ƒ váº«n cháº¡y Ä‘Æ°á»£c.\n\n| Code Smell | MÃ´ táº£ | VÃ­ dá»¥ |\n|-----------|-------|-------|\n| **Long Method** | HÃ m quÃ¡ dÃ i (>30 dÃ²ng) | `processOrder()` lÃ m 15 viá»‡c khÃ¡c nhau |\n| **God Class** | Class biáº¿t quÃ¡ nhiá»u, lÃ m quÃ¡ nhiá»u | `UserManager` xá»­ lÃ½ auth, profile, email, payment |\n| **Magic Numbers** | Sá»‘ literal khÃ´ng cÃ³ tÃªn | `if (status == 3)` â€” 3 lÃ  gÃ¬? |\n| **Duplicate Code** | Copy-paste code giá»‘ng nhau nhiá»u nÆ¡i | Validation logic láº·p láº¡i 5 chá»— |\n| **Feature Envy** | Method A dÃ¹ng dá»¯ liá»‡u cá»§a class B nhiá»u hÆ¡n class cá»§a nÃ³ | NÃªn chuyá»ƒn method sang class B |\n| **Long Parameter List** | HÃ m cÃ³ >4 tham sá»‘ | `createUser(name, email, age, phone, city, role)` |\n\n---\n\n## 3. CÃ¡c ká»¹ thuáº­t Refactoring phá»• biáº¿n\n\n**Refactoring** = thay Ä‘á»•i cáº¥u trÃºc code **mÃ  khÃ´ng thay Ä‘á»•i behavior** (cÃ³ test Ä‘á»ƒ Ä‘áº£m báº£o).\n\n```java\n// TRÆ¯á»šC refactoring â€” Magic number + Long method\npublic double calculatePrice(Order order) {\n    double price = order.basePrice;\n    if (order.quantity > 100) {\n        price *= 0.9; // magic number 0.9 lÃ  gÃ¬?\n    }\n    if (order.isVip) {\n        price *= 0.95;\n    }\n    if (order.coupon != null && order.coupon.isValid()) {\n        price -= order.coupon.discount;\n    }\n    return price * 1.1; // tax, magic number\n}\n\n// SAU refactoring â€” Extract Method + named constants\nprivate static final double BULK_DISCOUNT = 0.9;\nprivate static final int    BULK_THRESHOLD = 100;\nprivate static final double VIP_DISCOUNT   = 0.95;\nprivate static final double TAX_RATE       = 1.1;\n\npublic double calculatePrice(Order order) {\n    double price = order.basePrice;\n    price = applyBulkDiscount(order, price);\n    price = applyVipDiscount(order, price);\n    price = applyCoupon(order, price);\n    return applyTax(price);\n}\n\nprivate double applyBulkDiscount(Order o, double price) {\n    return o.quantity > BULK_THRESHOLD ? price * BULK_DISCOUNT : price;\n}\n// ... cÃ¡c hÃ m nhá» khÃ¡c\n```\n\n**Ká»¹ thuáº­t Refactoring phá»• biáº¿n:**\n- **Extract Method**: TÃ¡ch Ä‘oáº¡n code thÃ nh hÃ m nhá» cÃ³ tÃªn rÃµ rÃ ng.\n- **Rename Variable/Method**: Äáº·t tÃªn mÃ´ táº£ Ä‘Ãºng Ã½ nghÄ©a.\n- **Replace Magic Number**: DÃ¹ng constant cÃ³ tÃªn.\n- **Extract Class**: TÃ¡ch responsibility ra class riÃªng.\n- **Replace Conditional with Polymorphism**: Bá» if/switch, dÃ¹ng OOP.\n\n---\n\n## 4. Ná»£ Ká»¹ thuáº­t (Technical Debt)\n\nWard Cunningham (1992) Ä‘Æ°a ra khÃ¡i niá»‡m **Technical Debt** â€” áº©n dá»¥ tÃ i chÃ­nh: viáº¿t code nhanh, báº©n Ä‘á»ƒ ká»‹p deadline giá»‘ng nhÆ° vay ná»£. Ná»£ nÃ y pháº£i tráº£ báº±ng **effort refactoring sau**.\n\n### PhÃ¢n loáº¡i Technical Debt\n\n| Loáº¡i | MÃ´ táº£ | VÃ­ dá»¥ |\n|------|-------|-------|\n| **Deliberate** | Cá»‘ tÃ¬nh vÃ¬ Ã¡p lá»±c deadline | "Cá»© hardcode, sau refactor" |\n| **Inadvertent** | VÃ´ tÃ¬nh do thiáº¿u kiáº¿n thá»©c | DÃ¹ng Bubble Sort cho 1M records |\n| **Bit Rot** | Code tá»‘t nhÆ°ng environment thay Ä‘á»•i | ThÆ° viá»‡n deprecated khÃ´ng update |\n\n### CÃ¡ch Ä‘o Technical Debt\n- **SonarQube:** Tool tá»± Ä‘á»™ng scan code vÃ  Æ°á»›c tÃ­nh sá»‘ giá» cáº§n Ä‘á»ƒ fix smells.\n- **Code Complexity:** Cyclomatic complexity > 10 lÃ  dáº¥u hiá»‡u cáº§n refactor.\n\n### Quy táº¯c Boy Scout\n> "LuÃ´n Ä‘á»ƒ code sáº¡ch hÆ¡n so vá»›i khi báº¡n tÃ¬m tháº¥y nÃ³."\n\nMá»—i khi cháº¡m vÃ o má»™t file, dá»n dáº¹p má»™t chÃºt â€” khÃ´ng cáº§n refactor toÃ n bá»™ cÃ¹ng lÃºc. TÃ­ch lÅ©y dáº§n theo thá»i gian.',
